I think the best way to do it is to create a custom plugin, something like
```Javascript
app.directive('customCheck', function () {
 return {
	restrict: 'E',
	scope: {
	 predicate: '@'
	},
	require: '^stTable',
	template: '<input type="checkbox" ng-change="change()"/>',
	link: function (scope, element, attr, ctrl) {
	 scope.change = function change () {
		ctrl.search(element[0].value, scope.predicate);
	 }
	}
 }
});
```

which you would use
```
...
<th>
<custom-check predicate="myProp"></custom-check>
</th>
...
```

I have not actually tested it, so you might adjust a bit

ok with bb19a5778c2f451787dbd85533dd6b91976b7d55, the first call to pipe should be handled by the table. Note as mentioned @cadilhac if you were using the pagination directive, the table was kicked by itself and you should not had any problem. Now to prevent the pipe function to be called twice you'll have to set the initial pagination state in you pipe function:

```Javascript

function customPipe(tableState, ctrl){

//if you use the pagination directive make sure to set the initial pagination state to prevent a second initial //call from the pagination directive
if(!tableState.pagination.number){
tableState.pagination.number = 10;
tableState.pagination.start = 0;
}

//custom pipe logic

}
```

A bit hackish but I have not found better so far

